#include<bits/stdc++.h>
using namespace std;
const int N=300010;
int n,m,val[N],top[N],dfn[N],dfncnt,fa[N],siz[N],rnk[N],son[N],d[N];
vector<int> mp[N];
void dfs1(int x,int f=0)
{
    fa[x]=f;
    siz[x]=1;
    son[x]=-1;
    for(int i:mp[x])
    {
        if(i!=f)
        {
            d[i]=d[x]+1;
            dfs1(i,x);
            siz[x]+=siz[i];
            if(son[x]==-1||siz[i]>siz[son[x]])
            {
                son[x]=i;
            }
        }
    }
}
void dfs2(int x,int t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(int i:mp[x])
        {
            if(i!=fa[x]&&i!=son[x])
            {
                dfs2(i,i);
            }
        }
    }
}
struct segment_tree
{
    struct node
    {
        int l,r;
        int lson,rson;
        int sum,tag;
    }a[N*3];
    int cnt;
    segment_tree():cnt(0){}
    void pushup(int x)
    {
        a[x].sum=(a[a[x].lson].sum+a[a[x].rson].sum);
    }
    void pushadd(int x,int v)
    {
        if(!x)
        {
            return;
        }
        a[x].sum=(a[x].sum+(a[x].r-a[x].l+1)*v);
        a[x].tag=(a[x].tag+v);
    }
    void pushdown(int x)
    {
        int ls=a[x].lson,rs=a[x].rson;
        int tg=a[x].tag;
        pushadd(ls,tg);
        pushadd(rs,tg);
        a[x].tag=0;
    }
    int init(int l,int r)
    {
        int x=++cnt;
        a[x].l=l;
        a[x].r=r;
        a[x].tag=0;
        if(l==r)
        {
            a[x].sum=val[rnk[l]];
            return x;
        }
        int mid=(l+r)>>1;
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(int x,int l,int r,int v)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            pushadd(x,v);
            return;
        }
        pushdown(x);
        add(a[x].lson,l,r,v);
        add(a[x].rson,l,r,v);
        pushup(x);
    }
    int query(int x,int l,int r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        pushdown(x);
        return (query(a[x].lson,l,r)+query(a[x].rson,l,r));
    }
}t;
void add(int x,int y,int v)
{
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        t.add(1,dfn[top[x]],dfn[x],v);
        x=fa[top[x]];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    t.add(1,dfn[x]+1,dfn[y],v);
}
int getsum(int x,int y)
{
    int ans=0;
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        ans+=t.query(1,dfn[top[x]],dfn[x]);
        x=fa[top[x]];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    ans+=t.query(1,dfn[x]+1,dfn[y]);
    return ans;
}
int U[100010],V[100010],tot1;
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<n;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    dfs1(1);
    dfs2(1,1);
    t.init(1,n);
    for(int i=1;i<=m;i++)
    {
        char op;
        int x,y;
        cin>>op;
        scanf("%d",&x);
        if(op=='Q')
        {
            scanf("%d",&y);
            if(getsum(x,y)==0)
            {
                printf("Yes\n");
            }
            else
            {
                printf("No\n");
            }
        }
        else if(op=='C')
        {
            scanf("%d",&y);
            add(x,y,1);
            U[++tot1]=x;
            V[tot1]=y;
        }
        else
        {
            add(U[x],V[x],-1);
        }
    }
    return 0;
}
